"use client"

import { useState, useEffect, useCallback } from "react"
import {
  getPortfolioPosts,
  savePortfolioPost,
  hydrateStore,
  Post,
} from "@/lib/store"
import { useAdmin } from "@/lib/admin-context"
import { AdminLoginDialog } from "@/components/admin-login-dialog"
import { GalleryGrid } from "@/components/gallery-grid"
import { PostForm } from "@/components/post-form"

export default function PortfolioPage() {
  const { isAdmin } = useAdmin()
  const [posts, setPosts] = useState<Post[]>([])
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    setMounted(true)
  }, [])

  const loadPosts = useCallback(async () => {
    await hydrateStore()
    setPosts(getPortfolioPosts())
  }, [])

  useEffect(() => {
    void loadPosts()
  }, [loadPosts])

  const handleSubmit = (post: Post) => {
    savePortfolioPost(post)
    loadPosts()
  }

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div>
          <h1 className="text-2xl md:text-3xl font-bold text-foreground">포트폴리오</h1>
          <p className="mt-1 text-muted-foreground">
            다양한 작업물과 프로젝트를 확인하세요
          </p>
        </div>
        {mounted && (
          isAdmin ? (
            <PostForm onSubmit={handleSubmit} buttonLabel="포트폴리오 등록" />
          ) : (
            <AdminLoginDialog><span /></AdminLoginDialog>
          )
        )}
      </div>

      <GalleryGrid posts={posts} basePath="/portfolio" />
    </div>
  )
}
