"use client"

import { useState, useRef } from "react"
import Image from "next/image"
import { generateId } from "@/lib/store"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Textarea } from "@/components/ui/textarea"
import { Plus, X, Upload } from "lucide-react"

interface PostFormProps {
  onSubmit: (post: {
    id: string
    title: string
    description: string
    images: string[]
    createdAt: string
  }) => void
  buttonLabel?: string
}

export function PostForm({ onSubmit, buttonLabel = "새 글 작성" }: PostFormProps) {
  const [open, setOpen] = useState(false)
  const [title, setTitle] = useState("")
  const [description, setDescription] = useState("")
  const [images, setImages] = useState<string[]>([])
  const [isUploading, setIsUploading] = useState(false)
  const fileInputRef = useRef<HTMLInputElement>(null)

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files
    if (!files || files.length === 0) return

    setIsUploading(true)

    try {
      const MAX_WIDTH = 600
      const compressedImages: string[] = []

      for (const file of Array.from(files)) {
        const compressedBase64 = await new Promise<string>((resolve, reject) => {
          const reader = new FileReader()
          reader.onload = (event) => {
            const img = new window.Image()
            img.onload = () => {
              const canvas = document.createElement("canvas")
              let width = img.width
              let height = img.height

              if (width > MAX_WIDTH) {
                height = Math.round((height * MAX_WIDTH) / width)
                width = MAX_WIDTH
              }

              canvas.width = width
              canvas.height = height

              const ctx = canvas.getContext("2d")
              if (!ctx) {
                reject(new Error("Canvas context failed"))
                return
              }

              ctx.drawImage(img, 0, 0, width, height)
              resolve(canvas.toDataURL("image/webp", 0.5)) // Added harder compression
            }
            img.onerror = () => reject(new Error("Image load failed"))
            img.src = event.target?.result as string
          }
          reader.onerror = () => reject(new Error("File read failed"))
          reader.readAsDataURL(file)
        })
        compressedImages.push(compressedBase64)
      }

      setImages((prev) => [...prev, ...compressedImages])
    } catch (error) {
      console.error("Image upload processing error:", error)
      alert("이미지 처리 중 오류가 발생했습니다.")
    } finally {
      setIsUploading(false)
      if (fileInputRef.current) {
        fileInputRef.current.value = ""
      }
    }
  }

  const removeImage = (index: number) => {
    setImages((prev) => prev.filter((_, i) => i !== index))
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!title.trim() || images.length === 0) return

    onSubmit({
      id: generateId(),
      title: title.trim(),
      description: description.trim(),
      images,
      createdAt: new Date().toISOString(),
    })

    setTitle("")
    setDescription("")
    setImages([])
    setOpen(false)
  }

  const resetForm = () => {
    setTitle("")
    setDescription("")
    setImages([])
  }

  return (
    <Dialog open={open} onOpenChange={(o) => { setOpen(o); if (!o) resetForm() }}>
      <DialogTrigger asChild>
        <Button className="gap-2">
          <Plus className="w-4 h-4" />
          {buttonLabel}
        </Button>
      </DialogTrigger>
      <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto" aria-describedby={undefined}>
        <DialogHeader>
          <DialogTitle>새 글 작성</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <label className="text-sm font-medium">제목</label>
            <Input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="제목을 입력하세요"
              required
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium">설명</label>
            <Textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="설명을 입력하세요"
              rows={4}
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium">이미지</label>
            <div className="grid grid-cols-3 gap-2">
              {images.map((img, index) => (
                <div key={index} className="relative aspect-square rounded-lg overflow-hidden bg-muted">
                  <Image
                    src={img}
                    alt={`Upload ${index + 1}`}
                    fill
                    className="object-cover"
                  />
                  <Button
                    type="button"
                    variant="destructive"
                    size="icon"
                    className="absolute top-1 right-1 w-6 h-6"
                    onClick={() => removeImage(index)}
                  >
                    <X className="w-3 h-3" />
                  </Button>
                </div>
              ))}
              <button
                type="button"
                onClick={() => fileInputRef.current?.click()}
                disabled={isUploading}
                className="aspect-square rounded-lg border-2 border-dashed border-border hover:border-primary flex items-center justify-center transition-colors"
              >
                <Upload className="w-6 h-6 text-muted-foreground" />
              </button>
            </div>
            <input
              ref={fileInputRef}
              type="file"
              accept="image/*"
              multiple
              onChange={handleImageUpload}
              className="hidden"
            />
            <p className="text-xs text-muted-foreground">
              여러 이미지를 선택할 수 있습니다
            </p>
          </div>

          <div className="flex justify-end gap-2 pt-4">
            <Button type="button" variant="ghost" onClick={() => setOpen(false)}>
              취소
            </Button>
            <Button type="submit" disabled={!title.trim() || images.length === 0}>
              작성하기
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  )
}
